+### 17.16 Usage Example
+
+```rust
+// Create root layout
+let mut layout = Layout::new();
+
+// Split into header, main, footer
+layout.split_column(vec![
+    Layout::new().name("header").size(3),
+    Layout::new().name("main").ratio(1),
+    Layout::new().name("footer").size(10),
+]);
+
