+    fn render_leaf(
+        &self,
+        console: &Console,
+        options: &ConsoleOptions,
+        region: Region,
+    ) -> Vec<Vec<Segment<'static>>> {
+        let content_segments = if let Some(renderable) = self.renderable.as_ref() {
