+}
+
+fn build_column_with_content() -> Layout {
+    let mut layout = Layout::new();
+    layout.split_column(vec![
+        Layout::from_renderable(Text::new("TOP")).name("top"),
+        Layout::from_renderable(Text::new("BOTTOM")).name("bottom"),
+    ]);
+    layout
+}
